=grid($units, $grid-override: false)
  // Add padding to items on the grid.
  width: grid($units, $grid-mixin-counter + 1)
  @extend #{$object-type}column
  @if $grid-mixin-counter >= $columns
    $grid-mixin-counter: 0
  @if $grid-mixin-counter != 0
    @extend #{$object-type}next-column
  $grid-mixin-counter: $grid-mixin-counter + $units

@function modular-scale($multiple, $base-size, $ratio)
  // return the $base-size if $multiple is zero
  @if $multiple == 0
    @if type-of($base-size) == 'list'
      $base-size: sort-list($base-size)
      @return nth($base-size, 1)
    // return just the simple $base-size value if it's not a list
    @return $base-size

=grid-objects($prefix: a, $columns: $columns, $gutter: $gutter, $padding: $padding, $selector: "%")
  // counter keeps track of the starting position
  $count: 0
  @for $i from 1 through column-count($columns)
    @for $n from 1 through column-count($columns) - $count
      #{$selector}#{$prefix}#{$n}-#{$count + 1}
        +grid-span($n, $count + 1, $columns, $gutter, $padding)
    $count: $count + 1

=grid($units, $grid-override: false)
  // If object spans all columns
  @if $grid-override
    $grid-mixin-counter: $grid-override - 1
  @if $units == $columns
    +column
    +all-columns
  @else
    +column
    width: grid($units, $grid-mixin-counter + 1)
    // reset counters
    @if $grid-mixin-counter >= $columns
      $grid-mixin-counter: 0
    @if $grid-mixin-counter == 0
      +first-column
    $grid-mixin-counter: $grid-mixin-counter + $units

@function dip($number, $em-offset, $dip-conversion)
  $unitless-em-offset: $em-offset / 1em
  @if unitless($em-offset)
    $unitless-em-offset: $em-offset
  @if $dip-conversion == px
    @return $number * 1px
  @if $dip-conversion == em
    @return ($number / ($base-size / 1px)) * (1 / $unitless-em-offset) * 1em
  @if $dip-conversion == rem
    @return $number / ($base-size / 1px) * 1rem

=flex-directions($size)
  .direction-row-#{$size}
    flex-direction: row

  .direction-reverse-#{$size}
    flex-direction: row-reverse

  .direction-column-#{$size}
    flex-direction: column

  .direction-column-reverse-#{$size}
    flex-direction: column-reverse

=flex-directions($size)
  .frow.direction-row-#{$size}
    flex-direction: row

  .frow.direction-reverse-#{$size}
    flex-direction: row-reverse

  .frow.direction-column-#{$size}
    flex-direction: column

  .frow.direction-column-reverse-#{$size}
    flex-direction: column-reverse

@function findDarkColor($color)
  @if type-of($color) == 'color'
    $base-l: 29%
    $luminance: colorLuminance($color)
    $luminance-delta: (0.53 - $luminance)
    $target-l: round($base-l + ($luminance-delta * 53))
    @return change-color($color, $lightness: max($base-l, $target-l))
  @return $text-strong

@function findDarkColor($color, $base-l: 29%)
  @if type-of($color) == 'color'
    $luminance: colorLuminance($color)
    $luminance-delta: (0.53 - $luminance)
    $target-l: round($base-l + ($luminance-delta * 53))
    @return change-color($color, $lightness: max($base-l, $target-l))
  @return $text-strong

=breakpoint($name)
  $breakpoint: map-get($breakpoints, $name)
  @if $breakpoint
    $from: map-get($breakpoint, "from")
    $until: map-get($breakpoint, "until")
    @if $from and $until
      +between($from, $until)
        @content
    @else if $from
      +from($from)
        @content
    @else if $until
      +until($until)
        @content

